final_files.snippets/countdown-banner.liquid:
{% comment %} Countdown Banner Snippet {% endcomment %}

<div class="countdown-timer">
  <h2 class="countdown-heading">{{ settings.heading }}</h2>
  <div class="countdown-timer-container">
    <div class="timer-section">
      <span class="timer-value" id="days">{{ days }}</span>
      <span class="timer-label">Days</span>
    </div>
    <div class="timer-section">
      <span class="timer-value" id="hours">{{ hours }}</span>
      <span class="timer-label">Hours</span>
    </div>
    <div class="timer-section">
      <span class="timer-value" id="minutes">{{ minutes }}</span>
      <span class="timer-label">Minutes</span>
    </div>
    <div class="timer-section">
      <span class="timer-value" id="seconds">{{ seconds }}</span>
      <span class="timer-label">Seconds</span>
    </div>
  </div>
</div>

<script>
(function() {
  'use strict';

  const timerContainer = document.getElementById('countdown-timer');
  const endDate = '{{ settings.end_date }}';

  if (!timerContainer || !endDate) return;

  const end = new Date(endDate).getTime();

  const updateTimer = function() {
    const now = new Date().getTime();
    const distance = end - now;

    if (distance <= 0) {
      timerContainer.innerHTML = '<p class="countdown-message">Sale has ended!</p>';
      return;
    }

    const days = Math.floor(distance / (1000 * 60 * 60 * 24));
    const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
    const seconds = Math.floor((distance % (1000 * 60)) / 1000);

    document.getElementById('days').textContent = days < 10 ? '0' + days : days;
    document.getElementById('hours').textContent = hours < 10 ? '0' + hours : hours;
    document.getElementById('minutes').textContent = minutes < 10 ? '0' + minutes : minutes;
    document.getElementById('seconds').textContent = seconds < 10 ? '0' + seconds : seconds;
  };

  // Initial call
  updateTimer();

  // Update every second
  setInterval(updateTimer, 1000);
})();
</script>

<style>
.countdown-timer {
  padding: {{ settings.padding_block_start }}px {{ settings.padding_inline_start }}px;
  text-align: center;
}

.countdown-heading {
  color: {{ settings.text_color }};
  font-size: 1.5rem;
  font-weight: 600;
  margin: 0 0 24px 0;
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

.countdown-timer-container {
  display: flex;
  justify-content: center;
  gap: 24px;
  flex-wrap: wrap;
}

.timer-section {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.timer-value {
  font-size: 4rem;
  font-weight: 700;
  color: {{ settings.text_color }};
  line-height: 1;
  margin-bottom: 8px;
}

.timer-label {
  font-size: 0.875rem;
  color: {{ settings.text_color }};
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.countdown-message {
  color: {{ settings.text_color }};
  font-size: 1.25rem;
  font-weight: 500;
}

@media (max-width: 749px) {
  .countdown-timer {
    padding: {{ settings.padding_block_start }}px;
  }

  .countdown-heading {
    font-size: 1.25rem;
    margin-bottom: 16px;
  }

  .countdown-timer-container {
    gap: 16px;
  }

  .timer-value {
    font-size: 2.5rem;
    margin-bottom: 4px;
  }

  .timer-label {
    font-size: 0.75rem;
  }
}

@media (max-width: 479px) {
