<div class="section-background color-{{ section.settings.color_scheme }}"></div>
<div
  class="
    brand-values-section
    section
    section--{{ section.settings.section_width }}
    spacing-style
    gap-style
  "
  style="
    {% render 'spacing-style', settings: section.settings %}
    {% render 'gap-style', value: section.settings.gap %}
  "
  data-testid="brand-values"
>
  <div class="brand-values-section__content">
    {%- content_for 'blocks' -%}
  </div>
</div>

{% stylesheet %}
  .brand-values-section {
    display: grid;
    gap: var(--gap, 0);
    width: 100%;

    @media screen and (min-width: 750px) {
      grid-template-columns: repeat({{ columns }}, 1fr);
    }
  }

  .brand-values-section__content {
    width: 100%;
  }

  .brand-values-section .block {
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
  }

  .brand-values-section .icon {
    width: 48px;
    height: 48px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 16px;
  }

  .brand-values-section .icon img {
    width: 100%;
    height: 100%;
  }

  .brand-values-section .block__title {
    font-size: 1.5rem;
    font-weight: 700;
    margin-bottom: 8px;
    line-height: 1.2;
  }

  .brand-values-section .block__description {
    font-size: 1rem;
    line-height: 1.6;
    margin-bottom: 0;
  }

  .brand-values-section .block__description p {
    margin: 0;
  }

  @media screen and (max-width: 749px) {
    .brand-values-section {
      grid-template-columns: 1fr;
    }

    .brand-values-section .icon {
      width: 40px;
      height: 40px;
      margin-bottom: 12px;
    }
  }
{% endstylesheet %}

