final_files.blocks/value-card.liquid:
{% assign block_settings = block.settings %}
{% assign block_index = section.blocks | find_index: 'id', block.id %}

<div class="block">
  {% if block_settings.icon != blank %}
    <div class="icon">
      {{ block_settings.icon | image_url: width: 48 | image_tag: width: 48, height: 48, alt: block_settings.icon.alt, class: 'icon__image' }}
    </div>
  {% endif %}

  <div class="block__content">
    <h3 class="block__title">{{ block_settings.title }}</h3>
    <p class="block__description">{{ block_settings.description }}</p>
  </div>
</div>

{% stylesheet %}
  .block {
    display: flex;
    flex-direction: column;
    height: 100%;
    padding: {{ block_settings.padding_block_start }}px {{ block_settings.padding_inline_start }}px {{ block_settings.padding_block_end }}px {{ block_settings.padding_inline_end }}px;
    {% if block_settings.inherit_color_scheme == false %}
      color-{{ block_settings.color_scheme }};
    {% endif %}
    {% if block_settings.inherit_color_scheme == false %}
      background-color: {{ block_settings.color_scheme.settings.background.rgb }};
    {% endif %}
  }

  .block .icon {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: {{ block_settings.gap }}px;
  }

  .block .icon__image {
    width: 48px;
    height: 48px;
  }

  .block__content {
    display: flex;
    flex-direction: column;
    gap: {{ block_settings.gap }}px;
  }

  .block__title {
    font-size: {{ block_settings.font_size }}px;
    font-weight: {{ block_settings.font_weight }};
    line-height: {{ block_settings.line_height }};
    margin: 0;
  }

  .block__description {
    font-size: {{ block_settings.font_size }}px;
    line-height: {{ block_settings.line_height }};
    margin: 0;
    {% if block_settings.font_style != 'regular' %}
      font-family: {{ block_settings.font_style }};
    {% endif %}
  }

  @media screen and (max-width: 749px) {
    .block {
      padding: {{ block_settings.padding_block_start }}px {{ block_settings.padding_inline_start }}px {{ block_settings.padding_block_end }}px {{ block_settings.padding_inline_end }}px;
    }
  }
{% endstylesheet %}

